$ModulePath = Join-Path $PSScriptRoot 'DockerTagGenerator.psm1'
Import-Module $ModulePath -Force

Describe 'Get-DockerImageTags' {

    # ---------------------------------------------------------------------------
    # RED: main branch → latest
