            $gitContext = @{
                Branch    = 'main'
                CommitSha = 'cafebabe1234567'
                Tags      = @('v1.2.3')
                PrNumber  = $null
            }

            [string[]]$tags = Get-DockerImageTags -GitContext $gitContext

            $tags | Should -Contain 'latest'
            $tags | Should -Contain 'v1.2.3'
        }

        It 'handles multiple semver tags' {
            $gitContext = @{
                Branch    = 'main'
                CommitSha = 'cafebabe1234567'
